/*
 * COMP 321 Project 1: Factors
 *
 * This program computes the number of prime factors, and optionally the number
 * of distinct prime factors, for an unsigned integer input.
 * 
 * <Put your name and NetID here>
 */

#include <assert.h>
#include <math.h>     // Included in case you use the standard math library.
#include <stdbool.h>
#include <stdio.h>
#include <unistd.h>

static unsigned int	count_distinct_factors(unsigned int n);
static unsigned int	count_factors(unsigned int n);
static unsigned int	count_factors_recursive(unsigned int n);
static void		test_factors(void);

// Replace this comment with any global variable declarations.

/*
 * Requires:
 *   The input "n" must be greater than or equal to 1.
 *   The input "d" must be greater than or equal to 2.
 *
 * Effects:
 *   Returns the number of prime factors of "n", considering only
 *   potential divisors starting from "d".
 */
static unsigned int
count_factors_helper(unsigned int n, unsigned int d)
{

	if (n == 1)
		return (0);
	if (d > n / d)
		return (1);
	if (n % d == 0)
		return (1 + count_factors_helper(n / d, d));
	return (count_factors_helper(n, d + 1));
}

/* 
 * Requires:  
 *   The input "n" must be greater than 1.
 *
 * Effects: 
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors_recursive(unsigned int n)
{
	assert(n > 1);

	return (count_factors_helper(n, 2));
}

/*
 * Requires:
 *   The input "n" must be greater than 1.
 *
 * Effects:
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int d;

	assert(n > 1);

	for (d = 2; d <= n / d; d++) {
		while (n % d == 0) {
			count++;
			n /= d;
		}
	}
	if (n > 1)
		count++;

	return (count);
}

/*
 * Requires:
 *   The input "n" must be greater than 1.
 *
 * Effects:
 *   Returns the number of distinct factors of the input "n".
 */
static unsigned int
count_distinct_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int d;

	assert(n > 1);

	for (d = 2; d <= n / d; d++) {
		if (n % d == 0) {
			count++;
			while (n % d == 0)
				n /= d;
		}
	}
	if (n > 1)
		count++;

	return (count);
}

/* 
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Runs testing procedures.  Currently only prints a message.
 */
static void
test_factors(void)
{

	printf("Test Factors\n");
}

/* 
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   If the "-t" option is specified on the command line, then test code is
 *   executed and the program exits.
 *   
 *   Otherwise, requests a number from standard input.  If the "-r" option is
 *   specified on the command line, then prints the number of prime factors
 *   that the input number has, calculated using a recursive function.
 *   Otherwise, prints the number of prime factors that the input number has
 *   and the number of those factors that are distinct using iterative
 *   functions.
 *
 *   Upon completion, the program always returns 0.
 *
 *   If the number that is input is not between 2 and the largest unsigned
 *   integer, the output of the program is undefined, but it will not crash.
 */
int
main(int argc, char **argv)
{
	unsigned int n;
	int c;
	bool recursive = false;
	bool runtests = false;

	// Parse the command line.
	while ((c = getopt(argc, argv, "rt")) != -1) {
		switch (c) {
		case 'r':             // Use recursive version.
			recursive = true;
			break;
		case 't':             // Run test procedure and exit.
			runtests = true;
			break;
		default:
			break;
		}
	}

	// If "-t" is specified, run test procedure and exit program.
	if (runtests) {
		test_factors();
		return (0);
	}

	// Get input.
	printf("Enter number:\n");
	if (scanf("%u", &n) != 1) {
		fprintf(stderr, "Input error\n");
		return (1);
	}

	// Validate the input.
	if (n < 2) {
		fprintf(stderr, "Invalid input: %u\n", n);
		return (1);
	}

	// Print results.
	if (recursive) {
		// Use recursive version.
		printf("%u has %u prime factors.\n",
		    n, count_factors_recursive(n));
	} else {
		// Use iterative versions.
		printf("%u has %u prime factors, %u of them distinct.\n",
		    n, count_factors(n), count_distinct_factors(n));
	}

	// Report no errors.
	return (0);
}

"""
Agent tests for Project 1: Factors - edge cases and larger inputs.
"""

import sys
from pathlib import Path

_tests_dir = Path(__file__).parent.parent / "public"
if str(_tests_dir) not in sys.path:
    sys.path.insert(0, str(_tests_dir))

from fixtures import (
    make_test_result, run_program, compile_c_program,
    count_prime_factors, count_distinct_prime_factors
)

TEST_POINTS = {
    "test_factors_3": 1,
    "test_factors_4": 1,
    "test_factors_8": 1,
    "test_factors_100": 1,
    "test_factors_prime_large": 1,
    "test_factors_power_of_2": 1,
    "test_factors_large_composite": 1,
    "test_factors_prime_squared": 1,
    "test_factors_3_r": 1,
    "test_factors_100_r": 1,
    "test_factors_large_r": 1,
}


def _run_factors_test(workspace_path: Path, n: int, recursive: bool = False):
    executable = workspace_path / "factors"
    if not executable.exists():
        success, error = compile_c_program(workspace_path)
        if not success:
            return make_test_result(False, "compiled", "compilation failed", error)

    args = ["-r"] if recursive else []
    stdin_input = f"{n}\n"
    ret_code, stdout, stderr = run_program(executable, args, stdin_input, timeout=60)

    if ret_code != 0 and "Segmentation fault" not in stderr:
        return make_test_result(False, f"exit code 0", f"exit code {ret_code}", stderr)

    if recursive and "Segmentation fault" in stderr:
        if n > 1000000000:
            return make_test_result(True, "segfault (expected for large recursive)", "segfault", None)

    total_factors = count_prime_factors(n)
    distinct_factors = count_distinct_prime_factors(n)

    if recursive:
        expected_output = f"{n} has {total_factors} prime factors."
    else:
        expected_output = f"{n} has {total_factors} prime factors, {distinct_factors} of them distinct."

    if expected_output in stdout:
        return make_test_result(True, expected_output, stdout.strip(), None)
    else:
        return make_test_result(False, expected_output, stdout.strip(), None)


# Iterative tests
def test_factors_3(workspace):
    """Prime number 3."""
    return _run_factors_test(workspace, 3)

def test_factors_4(workspace):
    """4 = 2^2."""
    return _run_factors_test(workspace, 4)

def test_factors_8(workspace):
    """8 = 2^3."""
    return _run_factors_test(workspace, 8)

def test_factors_100(workspace):
    """100 = 2^2 * 5^2 (4 factors, 2 distinct)."""
    return _run_factors_test(workspace, 100)

def test_factors_prime_large(workspace):
    """Large prime 104729."""
    return _run_factors_test(workspace, 104729)

def test_factors_power_of_2(workspace):
    """2^20 = 1048576 (20 factors, 1 distinct)."""
    return _run_factors_test(workspace, 1048576)

def test_factors_large_composite(workspace):
    """2000000001 iterative."""
    return _run_factors_test(workspace, 2000000001)

def test_factors_prime_squared(workspace):
    """49 = 7^2 (2 factors, 1 distinct)."""
    return _run_factors_test(workspace, 49)

# Recursive tests
def test_factors_3_r(workspace):
    """Recursive: prime 3."""
    return _run_factors_test(workspace, 3, recursive=True)

def test_factors_100_r(workspace):
    """Recursive: 100."""
    return _run_factors_test(workspace, 100, recursive=True)

def test_factors_large_r(workspace):
    """Recursive: large number (may segfault)."""
    return _run_factors_test(workspace, 2000000001, recursive=True)
